def _coll():
    c = bpy.data.collections.get(WGT_COLL)
    if c is None:
        c = bpy.data.collections.new(WGT_COLL)
        bpy.context.scene.collection.children.link(c)
    try:
        c.hide_viewport = True
        c.hide_render = True
    except Exception:
        pass
    return c


def ensure(name):
    """Get-or-create OUR LOCAL widget object for custom_shape use.
    Never returns a library-linked object: a linked Storm rig in the file
    shares these names, and linked custom shapes break when the library
    moves. Our copies are tagged with the "sr_wgt" id property."""
    for ob in bpy.data.objects:
        if ob.library is None and ob.type == "MESH" and                 ob.get("sr_wgt") == name:
            return ob
    if name not in WIDGETS:
        return None
    v, e = WIDGETS[name]
    me = bpy.data.meshes.new(name)
    me.from_pydata(v, e, [])
    me.update()
    ob = bpy.data.objects.new(name, me)
    ob["sr_wgt"] = name
    _coll().objects.link(ob)
    return ob


def assign(rig, bone, wgt, scale=1.0, palette=None):
    """Assign a Storm widget + palette to a pose bone. scale may be a float
    or an (x, y, z) tuple, matching Storm custom_shape_scale_xyz."""
    pb = rig.pose.bones.get(bone)
    if pb is None:
        return False
    ob = ensure(wgt)
    if ob is None:
        return False
    pb.custom_shape = ob
    try:
        s = scale if isinstance(scale, (tuple, list)) else (scale,) * 3
        pb.custom_shape_scale_xyz = s
    except Exception:
        pass
    if palette:
        try:
            pb.color.palette = palette
            rig.data.bones[bone].color.palette = palette
        except Exception:
            pass
    return True
